import{_ as s,c as a,o as n,U as e}from"./chunks/framework.9QHaLlVJ.js";const k=JSON.parse('{"title":"IFS","description":"","frontmatter":{},"headers":[],"relativePath":"doc/Linux/基础/IFS.md","filePath":"packages/doc/src/Linux/基础/IFS.md","lastUpdated":1702833390000}'),t={name:"doc/Linux/基础/IFS.md"},p=e(`<h1 id="ifs" tabindex="-1">IFS <a class="header-anchor" href="#ifs" aria-label="Permalink to &quot;IFS&quot;">​</a></h1><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>IFS定义了在分隔单词时用作分隔的字符或字符集。</span></span>
<span class="line"><span>维基百科：对于Unix操作系统的许多命令行解释器(“shell”)，内部字段分隔符(简称IFS)是指一个变量，该变量定义用于将模式拆分为某些操作的标记的字符。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>默认情况下，IFS(字段分隔符)的值为&lt;space&gt;&lt;tab&gt;&lt;newline&gt;。因此，当shell看到第一行中的空格时，它将该行划分为四个标记(四个单词)。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>修改IFS的值来满足我们的需求</span></span>
<span class="line"><span>IFS是一个环境变量。在更改环境变量之前，最好的做法是保存它们的内容。这样就可以轻松地将它们设置为默认值。</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>像cat命令默认使用IFS指定分隔符进行读取，碰见一行内容有空格的就无法完整读取一行了。此时可以通过修改IFS来解决问题</p><h2 id="追加内容到文件末尾" tabindex="-1">追加内容到文件末尾 <a class="header-anchor" href="#追加内容到文件末尾" aria-label="Permalink to &quot;追加内容到文件末尾&quot;">​</a></h2><div class="language-shell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 读取文件</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">#   hosts=($(cat ./hosts))</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">#   echo \${hosts[*]}</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">#   for host in $hosts;do</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">#     {</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">#       # 遍历添加</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">#       echo -n &quot;\${host}&quot; &gt;&gt; \${HOST_PATH}</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">#     }</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">#   done</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p>#RUN apt install apt-transport-https ca-certificates #RUN cat /etc/issue #RUN cat /etc/os-release #RUN cat /etc/apt/sources.list</p><p>#open -a &quot;/Applications/Google Chrome.app&quot; &quot;<a href="http://localhost:9110" target="_blank" rel="noreferrer">http://localhost:9110</a>&quot; #open -a &quot;/Applications/Google Chrome.app&quot; &quot;<a href="http://localhost:9111" target="_blank" rel="noreferrer">http://localhost:9111</a>&quot; #open -a &quot;/Applications/Google Chrome.app&quot; &quot;<a href="http://localhost:8048" target="_blank" rel="noreferrer">http://localhost:8048</a>&quot;</p>`,7),l=[p];function i(r,o,c,h,d,u){return n(),a("div",null,l)}const m=s(t,[["render",i]]);export{k as __pageData,m as default};
